class CountIntervals {
    private int count = 0;
    private int[][] intervals;

    public CountIntervals() {
        intervals = new int[100005][2];
    }

    public void add(int left, int right) {
        int start = left;
        int end = right;
        for (int[] interval : intervals) {
            if (interval[0] != 0 && interval[0] <= end && interval[1] >= start) {
                start = Math.min(start, interval[0]);
                end = Math.max(end, interval[1]);
                interval[0] = 0;
                interval[1] = 0;
            }
        }
        for (int i = 0; i < intervals.length; i++) {
            if (intervals[i][0] == 0) {
                intervals[i][0] = start;
                intervals[i][1] = end;
                break;
            }
        }
        count = 0;
        for (int[] interval : intervals) {
            if (interval[0] != 0) {
                count += interval[1] - interval[0] + 1;
            }
        }
    }

    public int count() {
        return count;
    }
}
